import{_ as s,C as d,o as r,c as o,ag as t,E as n}from"./chunks/framework._658-eYr.js";const b=JSON.parse('{"title":"Episodes","description":"","frontmatter":{},"headers":[],"relativePath":"guide/episodes.md","filePath":"guide/episodes.md"}'),i={name:"guide/episodes.md"};function p(l,e,c,u,h,g){const a=d("SchemeImage");return r(),o("div",null,[e[0]||(e[0]=t('<h1 id="episodes" tabindex="-1">Episodes <a class="header-anchor" href="#episodes" aria-label="Permalink to &quot;Episodes&quot;">​</a></h1><p>Episodes represent complete video productions that move through an 8-stage content pipeline, fully orchestrated by AI agents with automated quality gates.</p><h2 id="pipeline-stages" tabindex="-1">Pipeline Stages <a class="header-anchor" href="#pipeline-stages" aria-label="Permalink to &quot;Pipeline Stages&quot;">​</a></h2><p>Each episode progresses through these stages sequentially. The <code>worker-orchestrate</code> service coordinates execution, invoking specialized agents and managing feedback loops automatically.</p><table tabindex="0"><thead><tr><th>Stage</th><th>Agent</th><th>Reviewer</th><th>Max Iterations</th><th>Description</th></tr></thead><tbody><tr><td><strong>Research</strong></td><td>Researcher</td><td>Producer</td><td>2</td><td>Gather facts, sources, competitive analysis, define unique angle</td></tr><tr><td><strong>Script</strong></td><td>Writer</td><td>Producer</td><td>3</td><td>Write screenplay in channel character voice</td></tr><tr><td><strong>Storyboard</strong></td><td>Storyboarder</td><td>Producer</td><td>2</td><td>Plan visual sequences and scene layouts</td></tr><tr><td><strong>Assets</strong></td><td>Asset Finder</td><td>—</td><td>1</td><td>Find and download media resources (stock footage, images, audio)</td></tr><tr><td><strong>Compositing</strong></td><td>Compositor</td><td>Producer</td><td>3</td><td>Assemble Remotion video composition from 65+ components</td></tr><tr><td><strong>Export</strong></td><td>Render Worker</td><td>—</td><td>1</td><td>Render final MP4 via Chromium (dispatched to <code>worker-render</code>)</td></tr><tr><td><strong>Review</strong></td><td>Producer</td><td>—</td><td>1</td><td>Holistic quality gate across all artifacts — always requires human approval</td></tr><tr><td><strong>Publish</strong></td><td>—</td><td>—</td><td>1</td><td>Guard on review approval, mark episode complete</td></tr></tbody></table><h2 id="execution-modes" tabindex="-1">Execution Modes <a class="header-anchor" href="#execution-modes" aria-label="Permalink to &quot;Execution Modes&quot;">​</a></h2><ul><li><strong>Full Pipeline</strong> — click &quot;Run Pipeline&quot; to execute from the next pending stage through to completion (or until a stage requires human intervention)</li><li><strong>Single Stage</strong> — click &quot;Run&quot; on any individual stage to execute just that stage</li></ul><h2 id="quality-gates" tabindex="-1">Quality Gates <a class="header-anchor" href="#quality-gates" aria-label="Permalink to &quot;Quality Gates&quot;">​</a></h2><p>The producer agent scores each stage output 1-10. Stages scoring 7+ pass automatically. Failed stages trigger a feedback loop:</p><ol><li>Producer writes structured revision notes</li><li>Notes are saved as stage feedback</li><li>The responsible agent re-runs with the feedback context</li><li>This repeats up to the stage&#39;s max iterations</li></ol><p>If max iterations are exhausted without passing, the stage is marked <code>needs_human</code> and the pipeline pauses for manual intervention.</p><h3 id="upstream-issues" tabindex="-1">Upstream Issues <a class="header-anchor" href="#upstream-issues" aria-label="Permalink to &quot;Upstream Issues&quot;">​</a></h3><p>If the producer identifies a problem originating from an earlier stage (e.g., a weak script caused by thin research), both the current stage and the upstream stage are marked <code>changes_requested</code>. The pipeline halts so a human can decide whether to re-run the upstream stage.</p><h3 id="soft-recovery" tabindex="-1">Soft Recovery <a class="header-anchor" href="#soft-recovery" aria-label="Permalink to &quot;Soft Recovery&quot;">​</a></h3><p>If an agent hits its turn limit but still produced the expected artifact (e.g., <code>research.md</code> exists), the orchestrator proceeds to review rather than hard-failing — the artifact may be good enough to pass.</p><h2 id="stage-statuses" tabindex="-1">Stage Statuses <a class="header-anchor" href="#stage-statuses" aria-label="Permalink to &quot;Stage Statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Color</th></tr></thead><tbody><tr><td><code>not_started</code></td><td>Stage hasn&#39;t been run</td><td>Gray</td></tr><tr><td><code>in_progress</code></td><td>Agent or render currently executing</td><td>Blue (pulsing)</td></tr><tr><td><code>review</code></td><td>Producer is evaluating the output</td><td>Yellow</td></tr><tr><td><code>complete</code></td><td>Stage passed quality gate</td><td>Green</td></tr><tr><td><code>approved</code></td><td>Human explicitly approved (review stage)</td><td>Green</td></tr><tr><td><code>changes_requested</code></td><td>Feedback provided, needs re-run</td><td>Gray</td></tr><tr><td><code>needs_human</code></td><td>Max iterations exhausted or human gate</td><td>Pink</td></tr><tr><td><code>error</code></td><td>Agent or render failed</td><td>Red</td></tr></tbody></table>',17)),n(a,{name:"episodes-panel",alt:"Episodes Panel"}),e[1]||(e[1]=t(`<h2 id="episode-files" tabindex="-1">Episode Files <a class="header-anchor" href="#episode-files" aria-label="Permalink to &quot;Episode Files&quot;">​</a></h2><p>Each episode lives in <code>channels/{channel}/episodes/{slug}/</code> with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>manifest.yml          # Pipeline state (stage statuses)</span></span>
<span class="line"><span>research.md           # Research output</span></span>
<span class="line"><span>script.md             # Written screenplay</span></span>
<span class="line"><span>storyboard.md         # Visual plan</span></span>
<span class="line"><span>Episode.tsx           # Remotion composition</span></span>
<span class="line"><span>feedback/             # Producer review notes per stage</span></span>
<span class="line"><span>  research.md</span></span>
<span class="line"><span>  script.md</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>output/               # Rendered video</span></span>
<span class="line"><span>  {slug}.mp4</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Episodes require NATS workers to be running. Start with <code>docker compose up -d</code>.</p></div>`,4))])}const f=s(i,[["render",p]]);export{b as __pageData,f as default};
